# Shapes module - implements geometric shapes using types module
from types import ShapeStatus, Point, IDrawable, IMeasurable, ITransformable

@abstract
class Shape(IDrawable, IMeasurable):
    name: str
    status: ShapeStatus
    _backed_status: str

    def __init__(self, name: str):
        self.name = name
        self.status = ShapeStatus.PENDING

    @virtual
    def draw(self) -> str:
        return "Shape: " + self.name

    @virtual
    def get_status(self) -> ShapeStatus:
        return self.status

    property get status_text(self) -> str:
        return str(self.status)

    def validate(self) -> None:
        self.status = ShapeStatus.VALID

class Rectangle(Shape, ITransformable):
    width: float
    height: float
    position: Point

    def __init__(self, width: float, height: float, pos: Point):
        super().__init__("Rectangle")
        self.width = width
        self.height = height
        self.position = pos
        self.validate()

    @override
    def draw(self) -> str:
        return "Rectangle[" + str(self.width) + "x" + str(self.height) + "] at " + self.position.formatted

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

class Circle(Shape, ITransformable):
    center: Point
    radius: float

    def __init__(self, center: Point, radius: float):
        super().__init__("Circle")
        self.center = center
        self.radius = radius
        self.validate()

    @override
    def draw(self) -> str:
        return "Circle[r=" + str(self.radius) + "] at " + self.center.formatted

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

class Triangle(Shape):
    p1: Point
    p2: Point
    p3: Point

    def __init__(self, p1: Point, p2: Point, p3: Point):
        super().__init__("Triangle")
        self.p1 = p1
        self.p2 = p2
        self.p3 = p3
        self.validate()

    @override
    def draw(self) -> str:
        return "Triangle at " + self.p1.formatted

    def area(self) -> float:
        # Using shoelace formula
        return abs((self.p1.x * (self.p2.y - self.p3.y) + self.p2.x * (self.p3.y - self.p1.y) + self.p3.x * (self.p1.y - self.p2.y)) / 2.0)

    def perimeter(self) -> float:
        return self.p1.distance_to(self.p2) + self.p2.distance_to(self.p3) + self.p3.distance_to(self.p1)

