# Utilities module - helper functions for shape operations
from types import ShapeStatus, Point, IMeasurable, ITransformable
from shapes import Shape, Rectangle, Circle, Triangle

def create_rectangle(w: float, h: float) -> Rectangle:
    origin: Point = Point(0.0, 0.0)
    return Rectangle(w, h, origin)

def create_circle(r: float) -> Circle:
    origin: Point = Point(0.0, 0.0)
    return Circle(origin, r)

def scale_shape(s: ITransformable, factor: float) -> None:
    s.scale(factor)

def measure_shape(m: IMeasurable) -> tuple[float, float]:
    return (m.area(), m.perimeter())

def check_status(s: Shape) -> str:
    # Use optional type for status check result
    if s.get_status() == ShapeStatus.VALID:
        return s.name + " is valid"
    else:
        return s.name + " is not valid"

def total_area(shapes: list[IMeasurable]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total

def process_shapes(shapes: list[Shape]) -> list[str]:
    results: list[str] = []
    for s in shapes:
        status: ShapeStatus = s.get_status()
        result: str = ""

        if status == ShapeStatus.VALID:
            result = "VALID: " + s.draw()
        elif status == ShapeStatus.PENDING:
            result = "PENDING: " + s.name
        elif status == ShapeStatus.INVALID:
            result = "INVALID: " + s.name
        else:
            result = "OTHER: " + s.name

        results.append(result)

    return results
